#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void Fan1(__global float *m_cuda, __global float *a_cuda, const int Size, const int t)
{
    int idx = get_global_id(0);
    if(idx >= Size - 1 - t) return;
    m_cuda[Size * (idx + t + 1) + t] = a_cuda[Size * (idx + t + 1) + t] / a_cuda[Size * t + t];
}

__kernel void Fan2(__global float *m_cuda, __global float *a_cuda, __global float *b_cuda, const int Size, const int j1, const int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    if(xidx >= Size - 1 - t) return;
    if(yidx >= Size - t) return;

    a_cuda[Size * (xidx + 1 + t) + (yidx + t)] -= m_cuda[Size * (xidx + 1 + t) + t] * a_cuda[Size * t + (yidx + t)];

    if(yidx == 0) {
        b_cuda[xidx + 1 + t] -= m_cuda[Size * (xidx + 1 + t) + t] * b_cuda[t];
    }
}
